void greeting(const char *name) {
 char buf[32];
 strcpy(buf, name);
 printf("Hello, %s!\n", buf);
}

int main(int argc, char *argv[]) {
 if (argc < 2){
 return 1;
 }
 greeting(argv[1]);
 return 0;
}
```

